### Fibonacci (Recursion)

```jac
# fibonacci.na.jac

def fib(n: int) -> int {
    if n <= 1 { return n; }
    return fib(n - 1) + fib(n - 2);
}

with entry {
    for i in range(10) {
        print(f"fib({i}) = {fib(i)}");
    }
}
```

### Lazy Iterators (map / filter / enumerate / zip)

```jac
# pipeline.na.jac

def double(x: int) -> int { return x * 2; }
def is_even(x: int) -> bool { return x % 2 == 0; }

with entry {
    nums: list[int] = [1, 2, 3, 4, 5, 6];

    # map and filter compose lazily, with no intermediate lists
    total: int = 0;
    for x in map(double, filter(is_even, nums)) {
        total = total + x;
    }
    print(f"sum of doubled evens: {total}");

    # enumerate and zip yield tuples unpacked in the loop header
    for (i, n) in enumerate(nums) {
        print(f"#{i}: {n}");
    }
    scores: list[int] = [10, 20, 30];
    for (n, s) in zip(nums, scores) {
        print(f"{n} scored {s}");
    }
}
```

### Objects and Inheritance

```jac
# animals.na.jac

obj Animal {
    has name: str;

    def speak() -> str {
        return "...";
    }
}

obj Dog(Animal) {
    def speak() -> str {
        return f"{self.name} says Woof!";
    }
}

obj Cat(Animal) {
    def speak() -> str {
        return f"{self.name} says Meow!";
    }
}

with entry {
    has animals: list[Animal] = [
        Dog(name="Rex"),
        Cat(name="Whiskers"),
        Dog(name="Buddy")
    ];

    for animal in animals {
        print(animal.speak());
    }
}
```

### Exception Handling

```jac
# safe_div.na.jac

def safe_divide(a: int, b: int) -> str {
    try {
        result = a // b;
        return f"{a} / {b} = {result}";
    } except ZeroDivisionError {
        return "Error: division by zero";
    }
}

with entry {
    print(safe_divide(10, 3));
    print(safe_divide(10, 0));
}
```

### Command-Line Tool with `sys.argv`

```jac
# greeter.na.jac
import sys;

with entry {
    args = sys.argv;
    if len(args) < 2 {
        print("Usage: greeter <name> [--shout]");
        sys.exit(1);
    }
    name = args[1];
    shout = "--shout" in args;
    greeting = f"Hello, {name}!";
    if shout {
        print(greeting.upper());
    } else {
        print(greeting);
    }
}
```

